form:Form.form:Scripts:
		var CFG;
var TIT=null;
var g_objEdit=null;

function InitEditor(objEdit)
{
 	//Agrego el CODIGO                             
 	objEdit.SetText(Ctrl("o_onchange").GetXValue());
 	objEdit.ReadOnly();

 	g_objEdit=objEdit;
}       

function EditEvento()
{
	var PARAM=new NomadXML("PARAM");                                           
	PARAM.SetAttr("oi_form", Ctrl("PARENT").GetXValue()); 
	PARAM.SetAttr("o_scripts_1", Ctrl("o_onchange").GetXValue());
	openNewFlowWait("NucleusWF.Base.Definicion.Workflows.FORM.flow","EditEvent",PARAM.ToString(),new objRefresh(), "L");
}

function objRefresh()
{                                                   
	this.processResult = function(xml)
	{
		var PARAM=new NomadXML(xml);
		if (PARAM.GetAttr("ACTION")=="ACCEPT")
		{
			Ctrl("o_onchange").SetXValue(PARAM.GetAttr("o_scripts_1"));
			g_objEdit.SetText(PARAM.GetAttr("o_scripts_1"));
		}
	}
}



function SAVE()
{
	//Valida caracteres especiales.
	var errorMessage = "El código no acepta alguno de los caracteres ingresados.";
  if(/(^([0-9,_,a-zA-Z])*$)/.test(Ctrl('c_form_group').GetXValue()))
  {
      Ctrl('main').DoEvent("SAVE");
  } 
  else 
  {
  	alert(errorMessage);
    return false;
  }  
}

