}

function ReplaceResource(recID) {
	var recValue=Ctrl("main").getResource(recID);
	recValue=Replace(recValue,"#RESOURCE-LIST#"  ,CFG.GetAttr("RESOURCE-LIST"  ));
	recValue=Replace(recValue,"#RESOURCE-ID#"    ,CFG.GetAttr("RESOURCE-ID"    ));
	recValue=Replace(recValue,"#RESOURCE-PARENT#",CFG.GetAttr("RESOURCE-PARENT"));
	recValue=Replace(recValue,"#RESOURCE-OBJECT#",CFG.GetAttr("RESOURCE-OBJECT"));

	Ctrl("main").setResource(recValue, recID);
}

function RefreshReport() {
	//Actualiza el reporte del formulario
	var strURL;

	strURL = "../../../ReportViewer.aspx?file=NucleusWF.Base.Definicion.WFPLA_Main.rpt" +
					"&ut=" + GetProxy().UserToken() +
					"&id=" + Ctrl("PARENT").GetXValue() +
					"&now=" + datetime2str(new Date());

	Ctrl("REPORT_ORG").SetURL(strURL);
}

