function CTRLCxMenu(pOI, pEvent) {
	Ctrl("GroupField_CM").SetXValue(pOI);
	Ctrl("GroupField_CM").OnContextMenu(pEvent);
}

function MainGroupCxMenu(pOI, pEvent) {
	Ctrl("MainGroup_CM").SetXValue(pOI);
	Ctrl("MainGroup_CM").OnContextMenu(pEvent);
}

function FormCxMenu(pOI, pEvent) {
	Ctrl("MainGroup_CM").SetXValue(pOI);
	Ctrl("MainGroup_CM").OnContextMenu(pEvent);
}


function FlowResult() {
	this.processResult = function(xml) {
		RefreshReport();
	}
}

