function OnChangeReport(obj)
{
	var retval="";
	if (obj.GetXValue()=="NOMAD")
	{ 
		retval+="report=[APP].[reporte]\n";

		Ctrl("o_text").SetXValue(retval);
	} else
	{
		var values=new NomadXML(Ctrl("main").GetLastDoc("REPORTES"));

		var value=values.FindElement2("option","value", obj.GetXValue());
		if (value==null || value.GetAttr("params")=="") return;

		var params=value.GetAttr("params").split(",");
		for (var t=0; t<params.length; t++)
			retval+=params[t]+"=\n";

		Ctrl("o_text").SetXValue(retval);
	}
}
